import{_ as n,C as o,o as r,c as l,a2 as t,j as e,a as s,G as h,w as d}from"./chunks/framework.BYVJ-AET.js";const E=JSON.parse('{"title":"Directory Trees","description":"","frontmatter":{},"headers":[],"relativePath":"repotools/6-docserver/2-dirtree.md","filePath":"repotools/6-docserver/2-dirtree.md","lastUpdated":1776092177000}'),p={name:"repotools/6-docserver/2-dirtree.md"};function c(g,i,k,u,m,f){const a=o("nobr");return r(),l("div",null,[i[6]||(i[6]=t('<h1 id="directory-trees" tabindex="-1">Directory Trees <a class="header-anchor" href="#directory-trees" aria-label="Permalink to &quot;Directory Trees&quot;">​</a></h1><p>The idea behind this plugin was inspired by <a href="https://tree.nathanfriend.com/?" target="_blank" rel="noreferrer">this</a> ASCII tree generator.</p><h2 id="plugin-structure" tabindex="-1">Plugin Structure <a class="header-anchor" href="#plugin-structure" aria-label="Permalink to &quot;Plugin Structure&quot;">​</a></h2><p>The plugin itself consists of 3 components:</p><h3 id="_1-markdown-it-plugin" tabindex="-1">1. <code>markdown-it</code> plugin <a class="header-anchor" href="#_1-markdown-it-plugin" aria-label="Permalink to &quot;1. `markdown-it` plugin&quot;">​</a></h3><p>This component hooks into the Markdown code block renderer, allowing us to replace the rendering logic for code blocks when we detect the <code>dirtree</code> language.</p><p>The directory plugin is located in the <code>markdown-tree</code> folder under the <code>lib</code> directory. Because of some of the <code>lodash</code> dependencies that get bundled, the plugin needs to be built to CJS rather than ESM.</p><details class="details custom-block"><summary>Creating a Markdown-It Plugin</summary><p>The documentation for developers looking to create a Markdown-It plugin are woefully inadequate. Thus, most of this plugin was written based on the implementations of other plugins, such as the Vitepress Mermaid plugin and Vitepress Code snippet plugin.</p></details><p>In this case, we first parse the YAML configuration, then render the directory tree as a string before passing it back to the Markdown code renderer so that the directory tree gets rendered as a code block.</p><h3 id="_2-textmate-grammar-for-the-dirtree-language" tabindex="-1">2. Textmate grammar for the <code>dirtree</code> language <a class="header-anchor" href="#_2-textmate-grammar-for-the-dirtree-language" aria-label="Permalink to &quot;2. Textmate grammar for the `dirtree` language&quot;">​</a></h3><p>To provide the colouring for the rendered directory trees, we first need to instruct Vitepress&#39; builtin highlighter <code>shiki</code> on how to parse our rendered directory trees so that it can figure out what elements need to be highlighted.</p><p><code>shiki</code> relies on <a href="https://macromates.com/manual/en/language_grammars" target="_blank" rel="noreferrer">Textmate Grammars</a> for parsing, so the plugin defines a grammar so that <code>shiki</code> can identify the different components of the directory tree:</p>',12)),e("table",null,[i[5]||(i[5]=e("thead",null,[e("tr",null,[e("th",null,"Component"),e("th",null,"Explanation"),e("th",null,"Examples")])],-1)),e("tbody",null,[i[3]||(i[3]=e("tr",null,[e("td",null,"Branch"),e("td",null,'Groups of 4 characters that together make up the graphic part of the "tree"'),e("td",null,[e("ul",null,[e("li",null,[e("code",null,"    ")]),e("li",null,[e("code",null,"│   ")]),e("li",null,[e("code",null,"├── ")]),e("li",null,[e("code",null,"└── ")])])])],-1)),i[4]||(i[4]=e("tr",null,[e("td",null,"Identifier"),e("td",null,"The name of a file or directory"),e("td",null,[e("ul",null,[e("li",null,[e("code",null,"filename.js")]),e("li",null,[e("code",null,"bin")])])])],-1)),e("tr",null,[i[1]||(i[1]=e("td",null,"Comment",-1)),i[2]||(i[2]=e("td",null,[s("Optional comment describing the entry, beginning with two forward slashes "),e("code",null,"//"),s(" that gets rendered at the end the line")],-1)),e("td",null,[h(a,null,{default:d(()=>i[0]||(i[0]=[e("code",null,"// This is a comment",-1)])),_:1,__:[0]})])])])]),i[7]||(i[7]=t(`<p>Each line in the directory must consist of at least 1 branch (if it&#39;s not the root) and exactly 1 identifier. The comment is optional.</p><p>Passing <code>shiki</code> this grammar also registers the <code>dirtree</code> langauge with <code>shiki</code>, so it doesn&#39;t get confused when trying to find highlighters.</p><h3 id="_3-highlighter-for-shiki" tabindex="-1">3. Highlighter for <code>shiki</code> <a class="header-anchor" href="#_3-highlighter-for-shiki" aria-label="Permalink to &quot;3. Highlighter for \`shiki\`&quot;">​</a></h3><p><code>shiki</code> uses the grammar to parse each line of the directory tree, which then breaks that line into an array of tokens that gets passed to the code transformer. Each token contains one of the aforementioned components.</p><p>Since each branch component has a length of 4, we can determine the level to which each token belongs by dividing its position from the start of the line by 4 (i.e a branch token at 8 characters offset from line start is at level 2). Then we simply assign the colour corresponding to that indent level to that token.</p><p>Vitepress uses the themes from Github by default, so the transformer is configured to select from a set of colours chosen from the <code>github-dark</code> and <code>github-light</code> themes.</p><h2 id="using-the-plugin-within-markdown" tabindex="-1">Using the plugin within Markdown <a class="header-anchor" href="#using-the-plugin-within-markdown" aria-label="Permalink to &quot;Using the plugin within Markdown&quot;">​</a></h2><p>To create your own directory tree, use the <code>dirtree</code> language with your markdown code block:</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line highlighted"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\`\`\` dirtree</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\`\`\`</span></span></code></pre></div><p>Within the <code>dirtree</code> code block, YAML is used for configuring the output. Start by first configuring your root object:</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\`\`\` dirtree</span></span>
<span class="line highlighted"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name: root directory</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\`\`\`</span></span></code></pre></div><p>If you do not specify a name for your root directory, then it will have the default name of <code>&quot;root&quot;</code>. Now you can proceed to create children elements using a YAML list:</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\`\`\` dirtree</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name: root directory</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">children:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - item0</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - name: item1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    children:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - item2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\`\`\`</span></span></code></pre></div><p>Each item can either just be a string entry (like <code>item0</code> above), in which case that entry is simply displayed as is, or it can be a compound YAML object like <code>item1</code> is. The details for such an entry are as follows:</p><div class="language-yml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">item1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # You must provide the name property</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">comment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">This is an optional comment</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">children</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Optional list of items</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">item2</span></span></code></pre></div><h2 id="optional-comments" tabindex="-1">Optional Comments <a class="header-anchor" href="#optional-comments" aria-label="Permalink to &quot;Optional Comments&quot;">​</a></h2><p>If provided, the comment is rendered on the same line, in alignment with all other comments:</p><div class="language-dirtree vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dirtree</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">root</span></span>
<span class="line"><span></span><span style="--shiki-light:#0366d6;--shiki-dark:#2188ff;">├── </span><span style="--shiki-light:#0366d6;--shiki-dark:#2188ff;">item1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                           // This is a comment</span></span>
<span class="line"><span></span><span style="--shiki-light:#0366d6;--shiki-dark:#2188ff;">├── </span><span style="--shiki-light:#0366d6;--shiki-dark:#2188ff;">item2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                           // Notice how all comments are</span></span>
<span class="line"><span></span><span style="--shiki-light:#0366d6;--shiki-dark:#2188ff;">│   </span><span style="--shiki-light:#5a32a3;--shiki-dark:#b392f0;">└── </span><span style="--shiki-light:#5a32a3;--shiki-dark:#b392f0;">item3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                       // aligned at the end</span></span>
<span class="line"><span></span><span style="--shiki-light:#0366d6;--shiki-dark:#2188ff;">└── </span><span style="--shiki-light:#0366d6;--shiki-dark:#2188ff;">this_item_has_a_very_long_name</span></span></code></pre></div><h2 id="path-validation" tabindex="-1">Path Validation <a class="header-anchor" href="#path-validation" aria-label="Permalink to &quot;Path Validation&quot;">​</a></h2><p>In the case you intend for your displayed directory tree to reflect the structure of an actual directory on disk, you can specify a <code>path</code> property on the root object. This path is resolved from the file containing the markdown.</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- Located in docs/index.md --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\`\`\` dirtree</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name: root directory</span></span>
<span class="line highlighted"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">path: ./root   # gets resolved to docs/root</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">children:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - item0</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - name: item1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    children:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - item2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\`\`\`</span></span></code></pre></div><p>The plugin will then traverse down the directory structure. For each item, if it has children, it checks that the item corresponds to a directory of the same name on disk. In the example above, the plugin would check that <code>docs/root</code> was a folder that contained either a file or directory called <code>item0</code>.</p><p>It would also check that <code>docs/root/item1</code> exists and that is is a directory (since it has children elements). This check is recursively performed on each subdirectory.</p><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>This validation is only performed for items that have been specified in the <code>dirtree</code>, i.e. it doesn&#39;t consider items that are present on disk but aren&#39;t listed as an issue.</p></div><p>If the check fails a warning will be printed to the console stating which files it wasn&#39;t able to locate.</p><p>Path validation is optional; Not providing a path means that no validation is performed, so <code>dirtree</code>s can reflect arbitrary directory structures.</p><h2 id="highlighting" tabindex="-1">Highlighting <a class="header-anchor" href="#highlighting" aria-label="Permalink to &quot;Highlighting&quot;">​</a></h2><p>Each level of nesting is given its own colour retrieved from the Github set of colours. Code highlighting in Vitepress is powered by <a href="https://shiki.style" target="_blank" rel="noreferrer"><code>shiki</code></a>. After the initial YML gets parsed and transformed into the raw uncoloured directory tree, the rendered code block gets passed to a code transformer, which parses the directory tree according to its own Textmate Grammar. Then, colours are applied to each line.</p><p>The grammar and code transformer are also exported from the Markdown Tree plugin and are applied in the Vitepress configuration. Refer to the <code>codeTransformers</code> and <code>languages</code> under the <code>markdown</code> set of options.</p><p>Do note that directory trees are intended to reflect actual structures within an actual file system. Therefore, if you use names for items that aren&#39;t valid as file names you might get incorrect highlighting.</p>`,30))])}const b=n(p,[["render",c]]);export{E as __pageData,b as default};
